class Solution {
public:
    int countSegments(string s) {
        int count = 0;
        bool prevSpace = true;
        for (char c : s) {
            if (c != ' ') {
                count++;
                prevSpace = false;
            } else if (!prevSpace) {
                prevSpace = true;
            }
        }
        return count;
    }
};
```

